-- Creates the territory tracker schema objects if needed and seeds 808 realtor ZIP rows.
DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'TerritoryTrackerTier') THEN
    CREATE TYPE "TerritoryTrackerTier" AS ENUM ('PREMIER', 'STANDARD', 'RURAL');
  END IF;
END
$$;

DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'TerritoryTrackerStatus') THEN
    CREATE TYPE "TerritoryTrackerStatus" AS ENUM ('AVAILABLE', 'RESERVED', 'SOLD');
  END IF;
END
$$;

CREATE TABLE IF NOT EXISTS "TerritoryTrackerEntry" (
  "id" UUID NOT NULL DEFAULT gen_random_uuid(),
  "zipCode" VARCHAR(5) NOT NULL,
  "city" TEXT NOT NULL,
  "county" TEXT NOT NULL,
  "population" INTEGER NOT NULL,
  "density" DOUBLE PRECISION NOT NULL,
  "tier" "TerritoryTrackerTier" NOT NULL,
  "status" "TerritoryTrackerStatus" NOT NULL DEFAULT 'AVAILABLE',
  "statusDate" TIMESTAMP(3),
  "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
  CONSTRAINT "TerritoryTrackerEntry_pkey" PRIMARY KEY ("id")
);

CREATE UNIQUE INDEX IF NOT EXISTS "TerritoryTrackerEntry_zipCode_key" ON "TerritoryTrackerEntry"("zipCode");
CREATE INDEX IF NOT EXISTS "TerritoryTrackerEntry_status_idx" ON "TerritoryTrackerEntry"("status");
CREATE INDEX IF NOT EXISTS "TerritoryTrackerEntry_tier_idx" ON "TerritoryTrackerEntry"("tier");
CREATE INDEX IF NOT EXISTS "TerritoryTrackerEntry_county_idx" ON "TerritoryTrackerEntry"("county");
CREATE INDEX IF NOT EXISTS "TerritoryTrackerEntry_city_idx" ON "TerritoryTrackerEntry"("city");

ON CONFLICT ("zipCode") DO UPDATE SET
  "city" = EXCLUDED."city",
  "county" = EXCLUDED."county",
  "population" = EXCLUDED."population",
  "density" = EXCLUDED."density",
  "tier" = EXCLUDED."tier",
  "status" = EXCLUDED."status",
  "statusDate" = EXCLUDED."statusDate",
  "updatedAt" = CURRENT_TIMESTAMP;
